function assertEvmChain(params, context) {
  const chain = params.chain ?? context.chain;
  if (chain.type !== "evm") {
    throw new KitError2({
      ...InputError2.INVALID_CHAIN,
      recoverability: "FATAL",
      message: `Expected EVM chain definition, but received chain type: ${chain.type}`
    });
  }
  return chain;
}
function getGatewayMinterAddress(chain) {
  if (!isGatewayV1Supported2(chain)) {
    throw new KitError2({
      ...InputError2.INVALID_CHAIN,
      recoverability: "FATAL",
      message: `Gateway Minter address not found: chain "${chain.name}" does not have Gateway v1 contracts configured.`,
      cause: { trace: { chain: chain.name } }
    });
  }
  return chain.gateway.contracts.v1.minter;
}
function getGatewayWalletAddress(chain) {
  if (!isGatewayV1Supported2(chain)) {
    throw new KitError2({
      ...InputError2.INVALID_CHAIN,
      recoverability: "FATAL",
      message: `Gateway Wallet address not found: chain "${chain.name}" does not have Gateway v1 contracts configured.`,
      cause: { trace: { chain: chain.name } }
    });
  }
  return chain.gateway.contracts.v1.wallet;
}
function resolveSignatureArgs(commonArgs, fields, functionName) {
  if (fields.signature !== void 0) {
    return [...commonArgs, fields.signature];
  }
  const missingComponents = [
    { name: "v", value: fields.v },
    { name: "r", value: fields.r },
    { name: "s", value: fields.s }
  ].filter((c) => c.value === void 0).map((c) => c.name);
  if (missingComponents.length === 3) {
    throw new KitError2({
      ...InputError2.VALIDATION_FAILED,
      recoverability: "FATAL",
      message: `${functionName} requires either signature bytes or v, r, s`
    });
  }
  const [firstMissing] = missingComponents;
  if (firstMissing !== void 0) {
    throw new KitError2({
      ...InputError2.VALIDATION_FAILED,
      recoverability: "FATAL",
      message: `${functionName}: missing signature component '${firstMissing}'`
    });
  }
  if (typeof fields.v !== "number") {
    throw new KitError2({
      ...InputError2.VALIDATION_FAILED,
      recoverability: "FATAL",
      message: `${functionName}: 'v' must be a number (27 or 28), got ${typeof fields.v}`
    });
  }
  if (typeof fields.r !== "string" || !fields.r.startsWith("0x")) {
    throw new KitError2({
      ...InputError2.VALIDATION_FAILED,
      recoverability: "FATAL",
      message: `${functionName}: 'r' must be a 0x-prefixed hex string`
    });
  }
  if (typeof fields.s !== "string" || !fields.s.startsWith("0x")) {
    throw new KitError2({
      ...InputError2.VALIDATION_FAILED,
      recoverability: "FATAL",
      message: `${functionName}: 's' must be a 0x-prefixed hex string`
    });
  }
  return [...commonArgs, fields.v, fields.r, fields.s];
}
